INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('b2e12cdd-a94d-59c9-84c5-9b0b66bf5b05', '564b45e7-8bd0-4007-9da6-95994a733bd7', 'The university provides many ___ resources, such as research journals and specialized libraries, to support students'' studies.', '這所大學提供許多學術資源，例如研究期刊和專業圖書館，以支持學生的學習。', 'academic', 'musical', 'physical', 'digital', 'academy (學院) + -ic (形容詞字尾，表示「...的」) → 學術的', '記住 academy 是「學院」，加上字尾 -ic 就變成了「學術的」。', '2026-07-06 16:22:24', '2026-07-06 16:22:24'),
('c46f435b-1532-59c2-bf16-00ca98def451', '672717a2-e182-485c-a892-959493e8a19b', '___ of the information provided in the brochure is useful.', '手冊中提供的所有資訊都很有用。', 'All', 'Few', 'Each', 'Both', '此處 all 作為代名詞，修飾不可數名詞 information，表示「全部」。', '看到 all 就要想到「全」，所有資訊就是 all information。', '2026-07-06 19:53:48', '2026-07-06 19:53:48'),
('93cd372c-b9c4-5226-9985-4b089aac0a65', 'd0a0589a-4329-4735-965b-933a3235dbd0', 'Is it ___ lunch time? I am so hungry!', '已經是午餐時間了嗎？我好餓！', 'already', 'maybe', 'often', 'slowly', '由 al (完全) 與 ready (準備好) 組成。', 'al (完全) + ready (準備好) → 事情已經完全準備好了 → 已經', '2026-07-06 13:53:24', '2026-07-06 13:53:24'),
('3278fd63-5d43-5797-b4df-33e02feb5b25', '0403b3ed-07cc-4c2f-9959-2c8124dcaae5', 'You should ___ to your teacher for being late to class.', '你應該為上課遲到向老師道歉。', 'apologize', 'celebrate', 'complain', 'prepare', 'apo (離開/去除) + log (說話) → 把話說清楚以消除錯誤 → 道歉', 'apologize 裡的 log 有說話的意思，把話說清楚來表示歉意 → 道歉', '2026-07-06 14:32:22', '2026-07-06 14:32:22'),
('b56ef69c-d115-57b8-952b-f94e4628db79', 'b51076ec-3758-4f79-a432-585767a67ace', 'The museum features a wide variety of modern ___ that attracts visitors from all over the world.', '這座博物館展出各式各樣的現代藝術，吸引了來自世界各地的訪客。', 'art', 'science', 'math', 'sports', 'art 源自拉丁語 ars，意為技術、技能或技巧。', '想像一個藝術家(artist)正在創作精美的藝術(art)。', '2026-07-07 00:20:24', '2026-07-07 00:20:24'),
('3584bff7-124c-574f-9a02-2aa7ee74495d', '49f7a8ca-2758-430e-97ac-a4b318a7adae', 'Stop acting like an ___ and start taking your studies seriously.', '別再表現得像個笨蛋，開始認真對待你的學業吧。', 'ass', 'angel', 'expert', 'actor', 'ass 為單字，在口語中常用來形容『笨蛋』或『固執自負的人』，原意亦指『驢子』。', '想像一隻倔強且笨拙的驢子 (ass) 拒絕學習，用來比喻不聽勸的笨蛋。', '2026-07-07 00:53:35', '2026-07-07 00:53:35'),
('06def078-d9fb-5562-a440-9a9c47a27259', '623f8fa2-fbda-45d5-a4a0-c57129458635', 'The podcast host uploaded the ___ files to the website so fans could listen to the interview.', '播客主持人將音訊檔案上傳到網站，以便粉絲可以收聽訪談。', 'audio', 'visual', 'formal', 'mental', 'root: audi- (聽/聽覺)', 'audi (聽) + o (形容詞字尾) → audio (聽覺的/音訊的). 聯想：audience (觀眾) 也是用來「聽」的人。', '2026-07-07 03:29:28', '2026-07-07 03:29:28'),
('24b13feb-fdec-5784-9933-f42185546659', '888135b3-ce40-4798-bef0-a1c7901fa3c3', 'She carries a heavy ___ on her shoulder.', '她在肩膀上背著一個沉重的袋子。', 'bag', 'shoe', 'spoon', 'clock', 'bag 為基本單字，本身即為字根。', '想像一個 bag (袋子) 裝滿東西後，背在肩膀上很重。', '2026-07-07 01:53:23', '2026-07-07 01:53:23'),
('c1eaa9b8-331a-55c9-a6b5-30cfd108e331', '6d5491db-6f00-47b1-becf-b7a5db5bd72d', 'The soldiers used a ___ to destroy the enemy''s bridge.', '士兵們使用炸彈來摧毀敵方的橋樑。', 'bomb', 'car', 'pen', 'cup', 'bomb 為基礎單字，當名詞時表示「炸彈」。', '想像 bomb 的發音像「波姆」，爆炸時發出的低沈聲響 → 炸彈。', '2026-07-07 05:00:03', '2026-07-07 05:00:03'),
('1bb7b692-0404-517f-97cb-52e8b42f4839', 'bd2d11dc-9059-4da5-a0f3-774ac4bf47a2', 'He used a large ___ to collect rainwater.', '他用一個大水桶來收集雨水。', 'bucket', 'bag', 'box', 'cup', 'bucket 為基礎名詞，無特定字根。', '想像在下雨時，拿著一個水桶 (bucket → 水桶) 去接雨水。', '2026-07-07 08:46:40', '2026-07-07 08:46:40'),
('6f4a0f83-520f-5d18-b272-0aee5bb01f7d', '4fd9a071-1d22-42ea-b9b3-a6cf76c5df2b', 'The students ___ the classroom before the bell rings.', '學生們在鈴聲響起前進入教室。', 'enter', 'leave', 'clean', 'break', 'en- (進入) + ter (來自拉丁語 intra，意為裡面)', 'enter 聯想 enter (進入) → 進入教室。', '2026-07-07 04:02:17', '2026-07-07 04:02:17'),
('927a2efd-0696-54ff-b0ed-2f66a7c510e5', '4943ce3b-dd4e-44e5-bcb0-0e2022f2ca81', 'It is hard to ___ animals on such a small piece of land.', '在這麼小的一塊土地上養殖動物是很困難的。', 'farm', 'sing', 'cook', 'sleep', 'farm 為基礎單字，無特定字根。', 'farm 當動詞時，代表「經營農場」或「從事畜牧業」→ 動作與土地有關。', '2026-07-07 05:00:16', '2026-07-07 05:00:16'),
('93f246b3-0910-5086-97ab-2de6761dfbb5', '831ead38-2c3b-499f-9c31-91f39dc8fab3', 'Eating too much ___ is bad for your health.', '吃太多速食對你的健康不好。', 'fast food', 'fruit', 'water', 'milk', 'fast (快的) + food (食物) → 速食', 'fast (快) + food (食物) = 快速提供的食物 → 速食', '2026-07-07 05:06:40', '2026-07-07 05:06:40'),
('b6ad275a-3172-5a8c-8029-328d14826a19', '17ef1527-7d04-4807-b2f2-725796032a8f', 'Can you ___ how soft this cat''s fur is?', '你能感覺到這隻貓的毛有多柔軟嗎？', 'feel', 'cook', 'read', 'drive', '無特定字根 (基礎動詞)', 'feel → 摸、感覺。', '2026-07-07 05:23:47', '2026-07-07 05:23:47'),
('fea305b0-dc45-579c-89a1-fbc0e632d0e5', 'c0215e23-91f1-4ae9-b39b-b68eff80cb98', 'I think it is ___ to travel to different countries to experience new cultures.', '我認為去不同的國家體驗新文化是很有趣的。', 'interesting', 'boring', 'dangerous', 'expensive', '字首 inter- (在...之間), 字根 est (存在), 字尾 -ing (令人...的)', 'interest (興趣) + ing (令人...的) → interesting (有趣的)', '2026-07-05 05:46:37', '2026-07-05 05:46:37'),
('c01b2a84-7403-58af-a038-2ea64e46d3c9', '4cb49395-91b8-403d-bb41-77e22ac4ae2f', 'It takes a lot of ___ to study hard.', '努力學習需要很大的意志力。', 'will', 'skill', 'luck', 'power', 'will 為單字，無詞根或詞綴。', 'will → 堅定的決心。', '2026-07-05 13:36:55', '2026-07-05 13:36:55');
